<script setup lang="ts">
import { onMounted, reactive, ref } from 'vue'; import { showFailToast,showSuccessToast } from 'vant'; import PageHeader from '../components/PageHeader.vue'; import { useAuthStore } from '../stores/auth'; import { getActiveActivity,getRecords,recordTemplate,saveToday } from '../services/api'; import type { DailyRecord } from '../types'; import { todayCN } from '../utils/date'
const auth=useAuthStore(); const loading=ref(false); const ready=ref(false); const form=reactive<DailyRecord>(recordTemplate('',0)); const meals=['正常','少吃','未吃','超量']
onMounted(async()=>{try{if(!auth.user)return; const {activity}=await getActiveActivity(auth.user.id); if(!activity)throw new Error('当前没有可打卡活动'); Object.assign(form,recordTemplate(auth.user.id,activity.id)); const records=await getRecords(auth.user.id,activity.id); const today=records.find(r=>r.record_date===todayCN()); if(today)Object.assign(form,today); ready.value=true}catch(e){showFailToast(e instanceof Error?e.message:'加载失败')}})
async function submit(){if(form.weight<=0)return showFailToast('体重必须大于 0'); if(form.sleep_hours<0||form.sleep_hours>24)return showFailToast('睡眠时长须为 0–24 小时'); if(form.exercise_minutes<0||form.water_ml<0)return showFailToast('数值不能小于 0'); loading.value=true; try{await saveToday({...form});showSuccessToast('今日打卡已保存')}catch(e){showFailToast(e instanceof Error?e.message:'保存失败')}finally{loading.value=false}}
</script>
<template><section class="page"><PageHeader eyebrow="DAILY CHECK-IN" title="今日打卡" back/><div v-if="ready" class="card"><van-form @submit="submit"><van-field :model-value="form.record_date" label="打卡日期" readonly/><van-field v-model.number="form.weight" type="number" label="当前体重" placeholder="例如 65.5" suffix="kg" required/><van-field v-model="form.breakfast_status" is-link readonly label="早餐"><template #input><van-radio-group v-model="form.breakfast_status" direction="horizontal"><van-radio v-for="m in meals" :key="m" :name="m">{{m}}</van-radio></van-radio-group></template></van-field><van-field v-model="form.lunch_status" label="午餐"><template #input><van-radio-group v-model="form.lunch_status" direction="horizontal"><van-radio v-for="m in meals" :key="m" :name="m">{{m}}</van-radio></van-radio-group></template></van-field><van-field v-model="form.dinner_status" label="晚餐"><template #input><van-radio-group v-model="form.dinner_status" direction="horizontal"><van-radio v-for="m in meals" :key="m" :name="m">{{m}}</van-radio></van-radio-group></template></van-field><van-field label="今天运动了吗"><template #input><van-switch v-model="form.exercised" size="22"/></template></van-field><template v-if="form.exercised"><van-field v-model="form.exercise_type" label="运动类型" placeholder="步行、跑步、游泳…"/><van-field v-model.number="form.exercise_minutes" type="number" label="运动时长" suffix="分钟"/></template><van-field v-model.number="form.water_ml" type="number" label="饮水量" suffix="ml"/><van-field v-model.number="form.sleep_hours" type="number" label="睡眠时长" suffix="小时"/><van-field label="今日完成"><template #input><van-switch v-model="form.completed" size="22"/></template></van-field><van-field v-model="form.remark" type="textarea" rows="3" maxlength="200" show-word-limit label="备注" placeholder="记录一下今天的感受"/><div class="form-actions"><van-button round block type="primary" native-type="submit" :loading="loading" :disabled="loading">保存今日打卡</van-button></div></van-form></div></section></template>
